# DONUT CHART  (reusable — takes any list of (label, value, colour) slices)
# ==============================================================================
class _DonutChart(QtWidgets.QWidget):
    def __init__(self, slices: list, centre_label: str = "Total", parent=None):
        super().__init__(parent)
        self.setMinimumSize(150, 150)
        self._slices = slices
        self._total = sum(s[1] for s in slices) or 1
        self._centre_label = centre_label

    def paintEvent(self, event):
        p = QtGui.QPainter(self)
        p.setRenderHint(QtGui.QPainter.RenderHint.Antialiasing)
        w, h = self.width(), self.height()
        size = min(w, h) - 14
        x = (w - size) // 2
        y = (h - size) // 2
        rect = QtCore.QRectF(x, y, size, size)
        start = 90 * 16
        for _, val, col in self._slices:
            span = int(round(val / self._total * 360 * 16))
            p.setBrush(QtGui.QColor(col))
            p.setPen(Qt.PenStyle.NoPen)
            p.drawPie(rect, start, -span)
            start -= span
        hole = size * 0.56
        hx = (w - hole) / 2
        hy = (h - hole) / 2
        p.setBrush(QtGui.QColor(_WHITE))
        p.drawEllipse(QtCore.QRectF(hx, hy, hole, hole))
        p.setPen(QtGui.QColor(_TEXT_DARK))
        p.setFont(QtGui.QFont("Segoe UI", 16, QtGui.QFont.Weight.Bold))
        p.drawText(QtCore.QRectF(hx, hy - 6, hole, hole / 2 + 6),
                   Qt.AlignmentFlag.AlignCenter, str(self._total))
        p.setFont(QtGui.QFont("Segoe UI", 8))
        p.setPen(QtGui.QColor(_TEXT_GREY))
        p.drawText(QtCore.QRectF(hx, hy + hole / 2 - 10, hole, 16),
                   Qt.AlignmentFlag.AlignCenter, self._centre_label)
        p.end()


# ==============================================================================
# LINE CHART  (Reports Trend — single series)
# ==============================================================================
class _LineChart(QtWidgets.QWidget):
    def __init__(self, x_labels: list, values: list, colour: str = "#5870ff",
                 y_max: int = 25, y_step: int = 5, parent=None):
        super().__init__(parent)
        self.setMinimumSize(240, 150)
        self._x_labels = x_labels
        self._values = values
        self._colour = colour
        self._y_max = y_max
        self._y_step = y_step

    def paintEvent(self, event):
        p = QtGui.QPainter(self)
        p.setRenderHint(QtGui.QPainter.RenderHint.Antialiasing)
        w, h = self.width(), self.height()
        m_left, m_right, m_top, m_bottom = 26, 10, 16, 22
        plot_w = w - m_left - m_right
        plot_h = h - m_top - m_bottom

        steps = self._y_max // self._y_step
        font_sm = QtGui.QFont("Segoe UI", 8)
        p.setFont(font_sm)
        for i in range(steps + 1):
            val = i * self._y_step
            gy = m_top + plot_h - (val / self._y_max) * plot_h
            p.setPen(QtGui.QColor(_BORDER))
            p.drawLine(QtCore.QPointF(m_left, gy), QtCore.QPointF(w - m_right, gy))
            p.setPen(QtGui.QColor(_TEXT_GREY))
            p.drawText(QtCore.QRectF(0, gy - 7, m_left - 5, 14),
                       Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter, str(val))

        n = len(self._x_labels)
        if n < 2:
            p.end()
            return
        step_x = plot_w / (n - 1)

        def xy(i, val):
            gx = m_left + i * step_x
            gy = m_top + plot_h - (val / self._y_max) * plot_h
            return QtCore.QPointF(gx, gy)

        pts = [xy(i, v) for i, v in enumerate(self._values)]

        path = QtGui.QPainterPath()
        path.moveTo(pts[0].x(), m_top + plot_h)
        for pt in pts:
            path.lineTo(pt)
        path.lineTo(pts[-1].x(), m_top + plot_h)
        path.closeSubpath()
        c = QtGui.QColor(self._colour)
        grad = QtGui.QLinearGradient(0, m_top, 0, m_top + plot_h)
        grad.setColorAt(0.0, QtGui.QColor(c.red(), c.green(), c.blue(), 70))
        grad.setColorAt(1.0, QtGui.QColor(c.red(), c.green(), c.blue(), 0))
        p.setBrush(QtGui.QBrush(grad))
        p.setPen(Qt.PenStyle.NoPen)
        p.drawPath(path)

        p.setPen(QtGui.QPen(QtGui.QColor(self._colour), 2))
        for i in range(len(pts) - 1):
            p.drawLine(pts[i], pts[i + 1])

        for i, val in enumerate(self._values):
            pt = pts[i]
            p.setBrush(QtGui.QColor(_WHITE))
            p.setPen(QtGui.QPen(QtGui.QColor(self._colour), 2))
            p.drawEllipse(pt, 4, 4)

            p.setPen(QtGui.QColor(_TEXT_DARK))
            p.setFont(QtGui.QFont("Segoe UI", 8, QtGui.QFont.Weight.Bold))
            p.drawText(QtCore.QRectF(pt.x() - 16, pt.y() - 20, 32, 16),
                       Qt.AlignmentFlag.AlignCenter, str(val))

            p.setPen(QtGui.QColor(_TEXT_GREY))
            p.setFont(font_sm)
            p.drawText(QtCore.QRectF(pt.x() - 20, m_top + plot_h + 4, 40, 14),
                       Qt.AlignmentFlag.AlignCenter, self._x_labels[i])
        p.end()


