    # ──────────────────────────────────────────────────────────────────────────
    # TABLE POPULATION
    # ──────────────────────────────────────────────────────────────────────────
    def _populate_table(self, data: list = None):
        rows = data if data is not None else self._reports
        self.table.setRowCount(0)
        for i, rec in enumerate(rows):
            (num, name, rtype, dept_scope, generated_by, generated_on,
             period, status) = rec
            self.table.insertRow(i)
            self.table.setRowHeight(i, 48)

            self._set_item(i, 0, str(i + 1))

            name_item = QtWidgets.QTableWidgetItem(name)
            name_item.setFlags(name_item.flags() & ~Qt.ItemFlag.ItemIsEditable)
            name_item.setFont(QtGui.QFont("Segoe UI", 11, QtGui.QFont.Weight.Bold))
            self.table.setItem(i, 1, name_item)

            self._set_item(i, 2, rtype)
            self._set_item(i, 3, dept_scope)
            self._set_item(i, 4, generated_by)
            self._set_item(i, 5, generated_on)
            self._set_item(i, 6, period)

            fg, bg = STATUS_COLOURS.get(status, (_TEXT_MID, "#f3f4f6"))
            self.table.setCellWidget(i, 7, self._centre(_Badge(status, fg, bg)))
            self.table.setCellWidget(i, 8, self._action_widget(i))

        count = len(rows)
        self.showing_lbl.setText(
            f"Showing 1 to {min(10, count)} of {count} reports")

    def _set_item(self, row, col, text):
        it = QtWidgets.QTableWidgetItem(text)
        it.setFlags(it.flags() & ~Qt.ItemFlag.ItemIsEditable)
        self.table.setItem(row, col, it)

    @staticmethod
    def _centre(widget) -> QtWidgets.QWidget:
        w = QtWidgets.QWidget()
        hl = QtWidgets.QHBoxLayout(w)
        hl.addWidget(widget)
        hl.setAlignment(Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignVCenter)
        hl.setContentsMargins(6, 0, 0, 0)
        return w

    def _action_widget(self, row: int) -> QtWidgets.QWidget:
        w = QtWidgets.QWidget()
        hl = QtWidgets.QHBoxLayout(w)
        hl.setContentsMargins(4, 0, 4, 0); hl.setSpacing(4)
        for ico, tip, col, slot in [
            ("👁", "View",     "#64748b", lambda _, r=row: self._on_view(r)),
            ("⬇",  "Download", "#0d9488", lambda _, r=row: self._on_download(r)),
            ("🗑",  "Delete",   "#dc2626", lambda _, r=row: self._on_delete(r)),
        ]:
            b = QtWidgets.QPushButton(ico)
            b.setFixedSize(24, 24)
            b.setToolTip(tip)
            b.setCursor(QtGui.QCursor(Qt.CursorShape.PointingHandCursor))
            b.setStyleSheet(f"""
                QPushButton {{
                    background:{col}22; color:{col};
                    border:1px solid {col}44;
                    border-radius:5px; font-size:11px;
                }}
                QPushButton:hover {{ background:{col}44; }}
            """)
            b.clicked.connect(slot)
            hl.addWidget(b)
        hl.addStretch()
        return w

    # ──────────────────────────────────────────────────────────────────────────
    # SLOTS
    # ──────────────────────────────────────────────────────────────────────────
    def _apply_filters(self):
        text = self.search_edit.text().lower()
        type_f = self._type_combo.currentText()
        dept_f = self._dept_combo.currentText()
        status_f = self._status_combo.currentText()
        results = []
        for rec in self._reports:
            (num, name, rtype, dept_scope, generated_by, generated_on,
             period, status) = rec
            if type_f != "All Types" and rtype != type_f: continue
            if dept_f != "All Departments" and dept_scope != dept_f: continue
            if status_f != "All Statuses" and status != status_f: continue
            if text and not any(text in v.lower() for v in
                                (name, rtype, dept_scope, generated_by)):
                continue
            results.append(rec)
        self._populate_table(results)

    def _on_add(self):
        dlg = GenerateReportDialog(self)
        dlg.report_saved.connect(self._append_report)
        dlg.exec()

    def _append_report(self, data: dict):
        from datetime import datetime
        new_num = len(self._reports) + 1
        gen_on = datetime.now().strftime("%d %b %Y %I:%M %p")
        self._reports.insert(0, (
            new_num, data["name"], data["report_type"], data["dept_scope"],
            data["generated_by"], gen_on, data["period_covered"], data["status"]
        ))
        self._apply_filters()
        QtWidgets.QMessageBox.information(
            self, "Report Generated",
            f"✅  '{data['name']}' has been generated successfully."
        )

    def _on_view(self, row: int):
        if row >= len(self._reports): return
        r = self._reports[row]
        QtWidgets.QMessageBox.information(
            self, "Report Details",
            f"<b>{r[1]}</b><br>Type: {r[2]}<br>Department / Scope: {r[3]}<br>"
            f"Generated By: {r[4]}<br>Generated On: {r[5]}<br>"
            f"Period Covered: {r[6]}<br>Status: {r[7]}"
        )

    def _on_download(self, row: int):
        if row >= len(self._reports): return
        name = self._reports[row][1]
        QtWidgets.QMessageBox.information(
            self, "Download Report",
            f"⬇  '{name}' will be downloaded once connected to the database "
            f"in the next sprint."
        )

    def _on_delete(self, row: int):
        if row >= len(self._reports): return
        name = self._reports[row][1]
        reply = QtWidgets.QMessageBox.question(
            self, "Delete Report",
            f"Delete <b>{name}</b>? This cannot be undone.",
            QtWidgets.QMessageBox.StandardButton.Yes |
            QtWidgets.QMessageBox.StandardButton.No,
            QtWidgets.QMessageBox.StandardButton.No,
        )
        if reply == QtWidgets.QMessageBox.StandardButton.Yes:
            self._reports.pop(row)
            self._apply_filters()

    def _on_filter_menu(self):
        QtWidgets.QMessageBox.information(
            self, "Advanced Filters",
            "Advanced filter panel will be available in the next sprint."
        )

    def _on_export(self):
        QtWidgets.QMessageBox.information(
            self, "Export",
            "Export functionality will be connected in the next sprint."
        )

    def _on_placeholder(self):
        QtWidgets.QMessageBox.information(
            self, "Coming Soon",
            "This feature will be available in the next sprint."
        )